CREATE TABLE assessments_to_security_requirements
(
	id serial,
	assessment_id integer NOT NULL,
	security_requirement_id integer DEFAULT NULL,

	CONSTRAINT pk_assessments_to_security_requirements PRIMARY KEY (id)
	, CONSTRAINT fk_assessments_to_security_requirements_to_assessment FOREIGN KEY (assessment_id) REFERENCES assessments (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_assessments_to_security_requirements_to_security_requirement FOREIGN KEY (security_requirement_id) REFERENCES security_requirements (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_assessments_to_security_requirements_assessment ON assessments_to_security_requirements (assessment_id);
CREATE INDEX i_assessments_to_security_requirements_security_requirement ON assessments_to_security_requirements (security_requirement_id);

ALTER TABLE security_requirements DROP COLUMN assessment_id;
